#!/usr/bin/env python3
import csv
import json
import os
import re
from collections import defaultdict, deque, Counter


ROOT = "/app"
PRODUCT_RE = re.compile(r"P_(\d+)")
STORE_RE = re.compile(r"S_(\d+)")
PRODUCER_RE = re.compile(r"PR_(\d+)")


def prod_key(pid):
    return int(pid.split("_")[1])


def store_key(sid):
    return int(sid.split("_")[1])


def producer_key(pid):
    return int(pid.split("_")[1])


def parse_day_name(name):
    m = re.search(r"day_(\d+)", name)
    if not m:
        raise ValueError(name)
    return int(m.group(1))


def parse_order_file(path):
    name = os.path.basename(path)
    day = parse_day_name(name)
    sm = re.search(r"(S_\d+)", name)
    if not sm:
        raise ValueError(path)
    store = sm.group(1)
    items = []
    if name.endswith(".json"):
        with open(path) as f:
            data = json.load(f)
        store = data["store_id"]
        day = int(re.search(r"\d+", data["date"]).group())
        items = [(x["prod_id"], int(x["qty"])) for x in data["items"]]
    elif "key-value" in name:
        pat = re.compile(r"ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)")
        with open(path) as f:
            for line in f:
                m = pat.search(line)
                if m:
                    items.append((m.group(1), int(m.group(2))))
    elif "table-csv" in name:
        with open(path, newline="") as f:
            reader = csv.DictReader(f, delimiter=";")
            for row in reader:
                items.append((row["PRODUCT"], int(row["QUANTITY"])))
    elif "text-template" in name:
        pat = re.compile(r"deliver\s+(\d+)\s+units of product\s+(P_\d+)", re.I)
        with open(path) as f:
            for line in f:
                m = pat.search(line)
                if m:
                    items.append((m.group(2), int(m.group(1))))
    else:
        raise ValueError(path)
    return day, store, items


def parse_supplier_file(path):
    name = os.path.basename(path)
    day = parse_day_name(name)
    pm = re.search(r"(PR_\d+)", name)
    if not pm:
        raise ValueError(path)
    producer = pm.group(1)
    items = []
    if name.endswith(".json"):
        with open(path) as f:
            data = json.load(f)
        producer = data["supplier_id"]
        day = int(re.search(r"\d+", data["date"]).group())
        items = [(x["prod_id"], int(x["delivered_qty"])) for x in data["items"]]
    elif "key-value" in name:
        pat_header = re.compile(r"SUPPLIER:\s*(PR_\d+)\s*\|\s*DAY:\s*(\d+)")
        pat = re.compile(r"PRODUCT:\s*(P_\d+)\s*\|\s*DELIVERED_QTY:\s*(\d+)")
        with open(path) as f:
            for line in f:
                hm = pat_header.search(line)
                if hm:
                    producer = hm.group(1)
                    day = int(hm.group(2))
                m = pat.search(line)
                if m:
                    items.append((m.group(1), int(m.group(2))))
    elif "table-csv" in name:
        with open(path, newline="") as f:
            reader = csv.DictReader(f, delimiter=";")
            for row in reader:
                items.append((row["PRODUCT"], int(row["DELIVERED_QTY"])))
    elif "text-template" in name:
        pat = re.compile(r"Supplier\s+(PR_\d+)\s+delivered\s+(\d+)\s+units of product\s+(P_\d+).*Day_(\d+)", re.I)
        with open(path) as f:
            text = f.read()
        for m in pat.finditer(text):
            producer = m.group(1)
            day = int(m.group(4))
            items.append((m.group(3), int(m.group(2))))
    else:
        raise ValueError(path)
    return day, producer, items


def parse_simple_receipt(path):
    values = {}
    with open(path) as f:
        for line in f:
            if ":" not in line:
                continue
            k, v = line.strip().split(":", 1)
            values[k.strip()] = v.strip()
    return values


def load_inputs():
    orders = {}
    for ent in os.scandir(os.path.join(ROOT, "raw_orders")):
        day, store, items = parse_order_file(ent.path)
        orders[(day, store)] = items

    supplier_docs = {}
    for ent in os.scandir(os.path.join(ROOT, "raw_supplier_receipts")):
        day, producer, items = parse_supplier_file(ent.path)
        supplier_docs[(day, producer)] = items

    supplier_seq = {}
    for ent in os.scandir(os.path.join(ROOT, "raw_wholesaler_receipts")):
        v = parse_simple_receipt(ent.path)
        supplier_seq[(int(v["DAY"]), v["SUPPLIER_ID"])] = int(v["DAILY_SEQUENCE_NO"])

    store_seq = {}
    store_total = {}
    for ent in os.scandir(os.path.join(ROOT, "raw_wholesaler_store_receipts")):
        v = parse_simple_receipt(ent.path)
        key = (int(v["DAY"]), v["STORE_ID"])
        store_seq[key] = int(v["DAILY_SEQUENCE_NO"])
        store_total[key] = int(v["TOTAL_DELIVERED_UNITS"])

    return orders, supplier_docs, supplier_seq, store_seq, store_total


def push_batch(q, batch):
    qty = batch["qty"]
    if qty <= 0:
        return
    if q and q[-1]["producer"] == batch["producer"] and q[-1]["day"] == batch["day"] and q[-1]["seq"] == batch["seq"]:
        q[-1]["qty"] += qty
    else:
        q.append(dict(batch))


def pop_batches(q, qty):
    out = []
    while qty > 0 and q:
        b = q[0]
        take = min(qty, b["qty"])
        out.append({"producer": b["producer"], "day": b["day"], "seq": b["seq"], "qty": take})
        b["qty"] -= take
        qty -= take
        if b["qty"] == 0:
            q.popleft()
    return out, qty


def build_store_deliveries(orders, supplier_docs, supplier_seq, store_seq, store_total):
    wh = defaultdict(deque)
    deliveries = defaultdict(lambda: defaultdict(list))
    mismatches = []
    for day in range(1, 366):
        # Supplier intake order is daily acceptance sequence; ties fall back to id for deterministic validation.
        recs = []
        for (d, producer), items in supplier_docs.items():
            if d == day:
                recs.append((supplier_seq[(d, producer)], producer, items))
        for seq, producer, items in sorted(recs, key=lambda x: (x[0], producer_key(x[1]))):
            for product, qty in items:
                push_batch(wh[product], {"producer": producer, "day": day, "seq": seq, "qty": qty})

        stores = []
        for (d, store), items in orders.items():
            if d == day:
                stores.append((store_seq[(d, store)], store, items))
        for sseq, store, items in sorted(stores, key=lambda x: (x[0], store_key(x[1]))):
            total = 0
            for product, qty in items:
                batches, short = pop_batches(wh[product], qty)
                got = qty - short
                total += got
                if got:
                    deliveries[(day, store)][product].extend(batches)
            expected = store_total[(day, store)]
            if total != expected:
                mismatches.append((day, store, total, expected))
    return deliveries, mismatches


def iter_sales_rows():
    with open(os.path.join(ROOT, "sales_log.csv"), newline="") as f:
        reader = csv.DictReader(f)
        current = None
        last_prod = 10**9
        consumer = 0
        for rownum, row in enumerate(reader, start=2):
            day = int(row["Day"])
            store = row["Store_ID"]
            key = (day, store)
            pnum = prod_key(row["Product_ID"])
            if key != current:
                current = key
                last_prod = 10**9
                consumer = 0
            if pnum <= last_prod:
                consumer += 1
            last_prod = pnum
            yield {
                "rownum": rownum,
                "day": day,
                "store": store,
                "consumer": consumer,
                "product": row["Product_ID"],
                "demand": int(row["Reported_Demand"]),
                "sold": int(row["Sold_Quantity"]),
                "lost": int(row["Lost_Sales"]),
            }


def trace_sales(deliveries):
    store_inv = defaultdict(lambda: defaultdict(deque))
    exposures = []
    stockout_rows = 0
    impossible_rows = []
    lost_with_stock = []
    row_count = 0
    sold_total = 0
    delivered_total = 0
    for day in range(1, 366):
        # Sales happen before same-day deliveries.
        for r in iter_sales_rows_for_day(day):
            row_count += 1
            q = store_inv[r["store"]][r["product"]]
            available_before = sum(b["qty"] for b in q)
            if r["sold"] > available_before:
                impossible_rows.append((r, available_before))
            if r["lost"] and available_before > r["sold"]:
                lost_with_stock.append((r, available_before))
            batches, short = pop_batches(q, r["sold"])
            if short:
                stockout_rows += 1
            for b in batches:
                sold_total += b["qty"]
                exposures.append((r["day"], r["store"], r["consumer"], r["product"], b["producer"], b["qty"], b["day"], b["seq"], r["demand"], r["sold"], r["lost"]))
        for (d, store), byprod in deliveries.items():
            if d != day:
                continue
            for product, batches in byprod.items():
                for b in batches:
                    delivered_total += b["qty"]
                    push_batch(store_inv[store][product], b)
    ending = sum(b["qty"] for byprod in store_inv.values() for q in byprod.values() for b in q)
    return {
        "exposures": exposures,
        "stockout_rows": stockout_rows,
        "impossible_rows": impossible_rows,
        "lost_with_stock": lost_with_stock,
        "row_count": row_count,
        "sold_total": sold_total,
        "delivered_total": delivered_total,
        "ending_store_inventory": ending,
    }


def iter_sales_rows_for_day(target_day):
    # The CSV is ordered by day, then store stream. This simple pass is acceptable for analysis
    # only if called once per day from trace_sales; avoid nested full scans.
    raise NotImplementedError


def load_sales_by_day():
    by_day = defaultdict(list)
    current = None
    last_prod = 10**9
    consumer = 0
    with open(os.path.join(ROOT, "sales_log.csv"), newline="") as f:
        reader = csv.DictReader(f)
        for rownum, row in enumerate(reader, start=2):
            day = int(row["Day"])
            store = row["Store_ID"]
            key = (day, store)
            pnum = prod_key(row["Product_ID"])
            if key != current:
                current = key
                last_prod = 10**9
                consumer = 0
            if pnum <= last_prod:
                consumer += 1
            last_prod = pnum
            by_day[day].append({
                "rownum": rownum,
                "day": day,
                "store": store,
                "consumer": consumer,
                "product": row["Product_ID"],
                "demand": int(row["Reported_Demand"]),
                "sold": int(row["Sold_Quantity"]),
                "lost": int(row["Lost_Sales"]),
            })
    return by_day


def trace_sales_from_by_day(deliveries, sales_by_day):
    store_inv = defaultdict(lambda: defaultdict(deque))
    exposures = []
    impossible_rows = []
    lost_with_stock = []
    row_count = 0
    sold_total = 0
    delivered_total = 0
    total_sales_sold = 0
    total_sales_lost = 0
    for day in range(1, 366):
        for r in sales_by_day[day]:
            row_count += 1
            total_sales_sold += r["sold"]
            total_sales_lost += r["lost"]
            q = store_inv[r["store"]][r["product"]]
            available_before = sum(b["qty"] for b in q)
            if r["sold"] > available_before:
                impossible_rows.append((r, available_before))
            if r["lost"] and available_before > r["sold"]:
                lost_with_stock.append((r, available_before))
            batches, short = pop_batches(q, r["sold"])
            for b in batches:
                sold_total += b["qty"]
                exposures.append({
                    "day": r["day"],
                    "store": r["store"],
                    "consumer": r["consumer"],
                    "product": r["product"],
                    "producer": b["producer"],
                    "qty": b["qty"],
                    "source_day": b["day"],
                    "source_seq": b["seq"],
                    "demand": r["demand"],
                    "sold": r["sold"],
                    "lost": r["lost"],
                    "rownum": r["rownum"],
                })
        for (d, store), byprod in deliveries.items():
            if d != day:
                continue
            for product, batches in byprod.items():
                for b in batches:
                    delivered_total += b["qty"]
                    push_batch(store_inv[store][product], b)
    ending = sum(b["qty"] for byprod in store_inv.values() for q in byprod.values() for b in q)
    return {
        "exposures": exposures,
        "impossible_rows": impossible_rows,
        "lost_with_stock": lost_with_stock,
        "row_count": row_count,
        "sold_total": sold_total,
        "sales_sold_total": total_sales_sold,
        "sales_lost_total": total_sales_lost,
        "delivered_total": delivered_total,
        "ending_store_inventory": ending,
    }


def main():
    orders, supplier_docs, supplier_seq, store_seq, store_total = load_inputs()
    print("orders", len(orders), "supplier_docs", len(supplier_docs), "supplier_seq", len(supplier_seq), "store_seq", len(store_seq))
    deliveries, mismatches = build_store_deliveries(orders, supplier_docs, supplier_seq, store_seq, store_total)
    print("allocation mismatches", len(mismatches))
    if mismatches[:10]:
        print("sample mismatches", mismatches[:10])
    sales_by_day = load_sales_by_day()
    print("sales days", len(sales_by_day), "rows", sum(len(v) for v in sales_by_day.values()))
    trace = trace_sales_from_by_day(deliveries, sales_by_day)
    for k in ["row_count", "sold_total", "sales_sold_total", "sales_lost_total", "delivered_total", "ending_store_inventory"]:
        print(k, trace[k])
    print("impossible_rows", len(trace["impossible_rows"]))
    print("lost_with_stock", len(trace["lost_with_stock"]))
    if trace["impossible_rows"][:5]:
        print("sample impossible", trace["impossible_rows"][:5])
    if trace["lost_with_stock"][:5]:
        print("sample lost_with_stock", trace["lost_with_stock"][:5])
    pc = Counter((e["product"], e["producer"]) for e in trace["exposures"])
    print("product-producer sold pairs", len(pc))
    print("first product producer counts", sorted(((p, pr, q) for (p, pr), q in pc.items() if p == "P_1"), key=lambda x: producer_key(x[1]))[:10])


if __name__ == "__main__":
    main()

